  ('dietitian-moex-11509', 'dietitian', 'dietitian-moex-092-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '現有一盤炒麵，用了油麵180公克，瘦肉60公克，蔬菜100公克，油1小匙，請問這盤炒麵約有多少大卡熱量？', '["450", "550", "650", "750"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "d5f7a6a3af3b", "answer_pdf_sha1": "19a7ca6319a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
