  ('dietitian-moex-11511', 'dietitian', 'dietitian-moex-092-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '現有 500 人用餐，每人平均食用 80 公克青江菜，若其廢棄率為 20%時，烹調增損率-8%，請問約需採購多少公斤青 江菜？', '["40.0", "50.0", "54.5", "59.5"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "d5f7a6a3af3b", "answer_pdf_sha1": "19a7ca6319a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11512', 'dietitian', 'dietitian-moex-092-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '200人自助餐菜單，葷菜為四選二，素菜為五選二，若設計四道葷菜、五道素菜，試列出葷素每道菜菜餚的份量？', '["每道葷菜份量=100份；每道素菜份量=80份", "每道葷菜份量=50份；每道素菜份量=40份", "每道葷菜份量=80份；每道素菜份量=100份", "每道葷菜份量=40份；每道素菜份量=50份"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "d5f7a6a3af3b", "answer_pdf_sha1": "19a7ca6319a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
